import styled from 'styled-components'

export const StyledNavbar = styled.div`
	background-color: #333;
	color: #fff;
	width: 100%;
	height: 5rem;

	ul {
		list-style-type: none;
		display: flex;
		flex-direction: row;
		justify-content: flex-end;
	}
  ul li {
    display: flex;
    justify-content: center;
    align-items: center;
  }






`
